package ru.memearena.tournament.application; import org.springframework.data.domain.*; import org.springframework.http.*; import org.springframework.stereotype.*; import org.springframework.transaction.annotation.*; import ru.memearena.error.*; import ru.memearena.meme.domain.*; import ru.memearena.meme.infrastructure.*; import ru.memearena.ranking.domain.WilsonScoreCalculator; import ru.memearena.tournament.domain.*; import ru.memearena.tournament.infrastructure.*; import java.time.*; import java.util.*;
@Service public class TournamentCreationService{ private final TournamentRepository tournaments; private final TournamentEntryRepository entries; private final TournamentMatchRepository matches; private final MemeRepository memes; private final TournamentProperties props; private final Clock clock; public TournamentCreationService(TournamentRepository t,TournamentEntryRepository e,TournamentMatchRepository m,MemeRepository memes,TournamentProperties p,Clock c){this.tournaments=t;this.entries=e;this.matches=m;this.memes=memes;this.props=p;this.clock=c;} @Transactional public Tournament createToday(){LocalDate d=LocalDate.now(clock.withZone(ZoneId.of(props.timeZone()))); return tournaments.findByTournamentDate(d).orElseGet(()->create(d));} private Tournament create(LocalDate d){Instant now=Instant.now(clock); Set<UUID> prev=tournaments.findFirstByOrderByTournamentDateDesc().map(x->entries.memeIds(x.id)).orElse(Set.of()); List<Meme> eligible=memes.findByModerationStatus(ModerationStatus.APPROVED,Pageable.unpaged()).stream().filter(m->m.getBattlesCount()>=props.minimumMemeBattles()).filter(m->!prev.contains(m.getId())).sorted(Comparator.<Meme>comparingDouble(m->WilsonScoreCalculator.lowerBound(m.getWins(),m.getLosses())).reversed().thenComparing(Meme::getRating,Comparator.reverseOrder()).thenComparing(Meme::getBattlesCount,Comparator.reverseOrder())).limit(props.participants()).toList(); if(eligible.size()<props.minimumParticipants()) throw new ApiException(HttpStatus.CONFLICT,ErrorCode.NOT_ENOUGH_TOURNAMENT_MEMES,"Not enough tournament memes"); Tournament t=tournaments.save(new Tournament(UUID.randomUUID(),d,now)); for(int i=0;i<eligible.size();i++) entries.save(new TournamentEntry(UUID.randomUUID(),t.id,eligible.get(i).getId(),i+1,now)); int total=props.participants(), mn=1; for(int i=1;i<=total/2;i++){UUID left=i<=eligible.size()?eligible.get(i-1).getId():null; int rs=total-i+1; UUID right=rs<=eligible.size()?eligible.get(rs-1).getId():null; TournamentMatchStatus st=(left==null||right==null)?TournamentMatchStatus.BYE:TournamentMatchStatus.ACTIVE; TournamentMatch m=new TournamentMatch(UUID.randomUUID(),t.id,1,mn++,left,right,st,now,now.plus(Duration.ofHours(props.roundDurationHours())),now); if(st==TournamentMatchStatus.BYE){m.winnerMemeId=left!=null?left:right; m.completedAt=now;} matches.save(m);} return t;} }
